function renderMarkdown(md) {
    if (!md) return null;
    const lines = md.split("\n");
    return h.jsx("div", {
        className: "space-y-4 text-sm text-zinc-700 dark:text-zinc-300 leading-relaxed max-h-[500px] overflow-y-auto p-4 border border-zinc-200 dark:border-white/10 rounded-xl bg-white dark:bg-zinc-900/50 custom-scrollbar",
        children: lines.map((line, idx) => {
            const trimmed = line.trim();
            if (trimmed.startsWith("# ")) {
                return h.jsx("h1", { className: "text-2xl font-bold text-zinc-950 dark:text-white border-b border-zinc-200 dark:border-white/10 pb-2 mt-4", children: trimmed.slice(2) }, idx);
            }
            if (trimmed.startsWith("## ")) {
                return h.jsx("h2", { className: "text-xl font-bold text-zinc-950 dark:text-white mt-4", children: trimmed.slice(3) }, idx);
            }
            if (trimmed.startsWith("### ")) {
                return h.jsx("h3", { className: "text-lg font-bold text-zinc-950 dark:text-white mt-3", children: trimmed.slice(4) }, idx);
            }
            if (trimmed.startsWith("* ") || trimmed.startsWith("- ")) {
                return h.jsx("li", { className: "ml-6 list-disc mt-1", children: trimmed.slice(2) }, idx);
            }
            if (trimmed.startsWith("➔")) {
                return h.jsx("p", { className: "text-zinc-500 font-bold", children: trimmed }, idx);
            }
            if (trimmed.startsWith("1. ") || trimmed.startsWith("2. ") || trimmed.startsWith("3. ") || trimmed.startsWith("4. ")) {
                return h.jsx("li", { className: "ml-6 list-decimal mt-1", children: trimmed.slice(3) }, idx);
            }
            if (trimmed === "---") {
                return h.jsx("hr", { className: "my-4 border-zinc-200 dark:border-white/10" }, idx);
            }
            if (trimmed.length === 0) return null;
            return h.jsx("p", { children: trimmed }, idx);
        }).filter(Boolean)
    });
}

